typedef struct
{
    uint8_t Handle;
    uint8_t Cell;
    uint32_t Size;
    uint32_t Flash_Start;
    uint32_t Flash_Size;
    uint32_t RAM_G_Start;
    uint32_t RAM_G_EndAddr;
    uint32_t Format;
    uint16_t Width;
    uint16_t Height;
    uint16_t CellHeight;
    uint32_t Palette;
    uint32_t Glyph_RAM_G_Start;
    uint32_t Glyph_Flash_Start;
    uint32_t Glyph_Flash_Size;
} EVE_ASSET_PROPS;
 
EVE_ASSET_PROPS heart_logo_RGB565; 
EVE_ASSET_PROPS Fredoka_Large;
EVE_ASSET_PROPS Fredoka_Small;
EVE_ASSET_PROPS Fredoka_Medium;
EVE_ASSET_PROPS grad_vert_L8;
EVE_ASSET_PROPS graph_L8;
EVE_ASSET_PROPS settings_L8;
EVE_ASSET_PROPS finger_L8;
EVE_ASSET_PROPS rotate_L8;
EVE_ASSET_PROPS volume_L8;

void set_asset_props(void)
{

    //images
    heart_logo_RGB565.Size = 69632;
    heart_logo_RGB565.Format = EVE_FORMAT_RGB565;
    heart_logo_RGB565.Width = 272;
    heart_logo_RGB565.Height = 128;

    grad_vert_L8.Size = 186;
    grad_vert_L8.Format = EVE_FORMAT_L8;
    grad_vert_L8.Width = 1;
    grad_vert_L8.Height = 186;

    graph_L8.Size = 256;
    graph_L8.Format = EVE_FORMAT_L8;
    graph_L8.Width = 16;
    graph_L8.Height = 16;

    settings_L8.Size = 1024;
    settings_L8.Format = EVE_FORMAT_L8;
    settings_L8.Width = 32;
    settings_L8.Height = 32;

    finger_L8.Size = 8100;
    finger_L8.Format = EVE_FORMAT_L8;
    finger_L8.Width = 90;
    finger_L8.Height = 90;

    rotate_L8.Size = 2500;
    rotate_L8.Format = EVE_FORMAT_L8;
    rotate_L8.Width = 50;
    rotate_L8.Height = 50;

    volume_L8.Size = 5000;
    volume_L8.Format = EVE_FORMAT_L8;
    volume_L8.Width = 50;
    volume_L8.Height = 100;
    volume_L8.CellHeight = 50; // this bitmap has two cells so set the cell height also

    //fonts
    Fredoka_Large.Size = 17308; // size includes font metric block
    Fredoka_Large.Format = EVE_FORMAT_L4;

    Fredoka_Medium.Size = 44232; // size includes font metric block
    Fredoka_Medium.Format = EVE_FORMAT_L4;

    Fredoka_Small.Size = 10123; // size includes font metric block
    Fredoka_Small.Format = EVE_FORMAT_L4;


}


// ######################################################################################################################################################################################################
// #######################################################                      Code for the Widgets Example                          ###################################################################
// ######################################################################################################################################################################################################


uint32_t eve_display_load_assets(void)
{
    DEBUG_PRINTF("Loading assets...\n");

    //set asset properties
    set_asset_props();

    // heart logo
    heart_logo_RGB565.RAM_G_Start = 0;
    heart_logo_RGB565.Handle = BITMAP_HEART;
    EVE_LIB_WriteDataToRAMG(heart_logo, heart_logo_RGB565.Size, heart_logo_RGB565.RAM_G_Start);

    // large font
    Fredoka_Large.RAM_G_Start = heart_logo_RGB565.RAM_G_Start + heart_logo_RGB565.Size;
    Fredoka_Large.Handle = FONT_LARGE;
    EVE_LIB_WriteDataToRAMG(Fredoka_SemiBold, Fredoka_Large.Size, Fredoka_Large.RAM_G_Start);

    // adjust ram_G offset used in the conversion to where we have actually loaded this into RAM_G
    EVE_LIB_MemWrite32((Fredoka_Large.RAM_G_Start + 144), (Fredoka_Large.RAM_G_Start + 148)); 

    // medium font
    Fredoka_Medium.RAM_G_Start = Fredoka_Large.RAM_G_Start + Fredoka_Large.Size;
    Fredoka_Medium.Handle = FONT_MEDIUM;
    EVE_LIB_WriteDataToRAMG(Fredoka_Medium_28, Fredoka_Medium.Size, Fredoka_Medium.RAM_G_Start);

    // adjust ram_G offset used in the conversion to where we have actually loaded this into RAM_G
    EVE_LIB_MemWrite32((Fredoka_Medium.RAM_G_Start + 144), (Fredoka_Medium.RAM_G_Start + 148)); 
  
    // small font
    Fredoka_Small.RAM_G_Start = Fredoka_Medium.RAM_G_Start + Fredoka_Medium.Size;
    Fredoka_Small.Handle = FONT_SMALL;
    EVE_LIB_WriteDataToRAMG(Fredoka_Medium_14, Fredoka_Small.Size, Fredoka_Small.RAM_G_Start);

    // adjust ram_G offset used in the conversion to where we have actually loaded this into RAM_G
    EVE_LIB_MemWrite32((Fredoka_Small.RAM_G_Start + 144), (Fredoka_Small.RAM_G_Start + 148)); 

    // vertical gradient
    grad_vert_L8.RAM_G_Start = Fredoka_Small.RAM_G_Start + Fredoka_Small.Size;
    grad_vert_L8.Handle = BITMAP_GRAD;
    EVE_LIB_WriteDataToRAMG(grad_vert, grad_vert_L8.Size, grad_vert_L8.RAM_G_Start);

    // graph lines
    graph_L8.RAM_G_Start = grad_vert_L8.RAM_G_Start + grad_vert_L8.Size;
    graph_L8.Handle = BITMAP_GRAPH;
    EVE_LIB_WriteDataToRAMG(graph, graph_L8.Size, graph_L8.RAM_G_Start);

    // settings icon
    settings_L8.RAM_G_Start = graph_L8.RAM_G_Start + graph_L8.Size;
    settings_L8.Handle = BITMAP_SETTINGS;
    EVE_LIB_WriteDataToRAMG(settings, settings_L8.Size, settings_L8.RAM_G_Start);

    // finger icon
    finger_L8.RAM_G_Start = settings_L8.RAM_G_Start + settings_L8.Size;
    finger_L8.Handle = BITMAP_FINGER;
    EVE_LIB_WriteDataToRAMG(finger, finger_L8.Size, finger_L8.RAM_G_Start);

    // rotate icon
    rotate_L8.RAM_G_Start = finger_L8.RAM_G_Start + finger_L8.Size;
    rotate_L8.Handle = BITMAP_ROTATE;
    EVE_LIB_WriteDataToRAMG(rotate, rotate_L8.Size, rotate_L8.RAM_G_Start);

    // volume icons (this bitmap has two cells)
    volume_L8.RAM_G_Start = rotate_L8.RAM_G_Start + rotate_L8.Size;
    volume_L8.Handle = BITMAP_VOLUME;
    EVE_LIB_WriteDataToRAMG(volume, volume_L8.Size, volume_L8.RAM_G_Start);

    // co-processor list to configure bitmpa and font properties
    EVE_LIB_BeginCoProList();
    EVE_CMD_DLSTART();

    //configure bitmaps
    EVE_BITMAP_HANDLE(heart_logo_RGB565.Handle);
    EVE_CMD_SETBITMAP(heart_logo_RGB565.RAM_G_Start, heart_logo_RGB565.Format, heart_logo_RGB565.Width, heart_logo_RGB565.Height);

    EVE_BITMAP_HANDLE(grad_vert_L8.Handle);
    EVE_CMD_SETBITMAP(grad_vert_L8.RAM_G_Start, grad_vert_L8.Format, grad_vert_L8.Width, grad_vert_L8.Height);

    EVE_BITMAP_HANDLE(graph_L8.Handle);
    EVE_CMD_SETBITMAP(graph_L8.RAM_G_Start, graph_L8.Format, graph_L8.Width, graph_L8.Height);

    EVE_BITMAP_HANDLE(settings_L8.Handle);
    EVE_CMD_SETBITMAP(settings_L8.RAM_G_Start, settings_L8.Format, settings_L8.Width, settings_L8.Height);

    EVE_BITMAP_HANDLE(finger_L8.Handle);
    EVE_CMD_SETBITMAP(finger_L8.RAM_G_Start, finger_L8.Format, finger_L8.Width, finger_L8.Height);

    EVE_BITMAP_HANDLE(rotate_L8.Handle);
    EVE_CMD_SETBITMAP(rotate_L8.RAM_G_Start, rotate_L8.Format, rotate_L8.Width, rotate_L8.Height);

    EVE_BITMAP_HANDLE(volume_L8.Handle);
    EVE_CMD_SETBITMAP(volume_L8.RAM_G_Start, volume_L8.Format, volume_L8.Width, volume_L8.CellHeight); // this bbitmap has two cells so use the cell height here

    // configure fonts
    EVE_CMD_SETFONT2(Fredoka_Large.Handle, Fredoka_Large.RAM_G_Start, 48); //use 48 here as we only converted the 0-9 chars
    EVE_CMD_SETFONT2(Fredoka_Medium.Handle, Fredoka_Medium.RAM_G_Start, 32); 
    EVE_CMD_SETFONT2(Fredoka_Small.Handle, Fredoka_Small.RAM_G_Start, 32); 
    
    EVE_DISPLAY();
    EVE_DISPLAY(); // per BRT_TN_005
    EVE_CMD_SWAP();
    EVE_LIB_EndCoProList();
    EVE_LIB_AwaitCoProEmpty();

    DEBUG_PRINTF("Done.\n");

    // return the next free area in RAM_G
    return (volume_L8.RAM_G_Start + volume_L8.Size);
}
